            <set-variable name="rdwrRenderedBlockPage" value="@{
              string template = @"


403 Forbidden




403 Forbidden

Your request has been blocked by our security system.

Transaction ID: [%transaction_id%]

[%timestamp%]
";
              // Extract transaction ID from SP body
              string transId = "";
              try {
                string body = (string)context.Variables.GetValueOrDefault("radwareResponseBody", "");
                if (!string.IsNullOrEmpty(body)) {
                  // Pattern 1: _event_transid='...'
                  int idx = body.IndexOf("_event_transid='");
                  if (idx >= 0) {
                    int start = idx + 16;
                    int end = body.IndexOf("'", start);
                    if (end > start) { transId = body.Substring(start, end - start); }
                  }
                  // Pattern 2: "transid":"..."
                  if (string.IsNullOrEmpty(transId)) {
                    idx = body.IndexOf("\"transid\"");
                    if (idx >= 0) {
                      int qStart = body.IndexOf("\"", idx + 9 + body.Substring(idx + 9).IndexOf(":") + 1);
                      if (qStart >= 0) {
                        int qEnd = body.IndexOf("\"", qStart + 1);
                        if (qEnd > qStart + 1) { transId = body.Substring(qStart + 1, qEnd - qStart - 1); }
                      }
                    }
                  }
                }
              } catch {}
              // Build rendered page with token substitution
              string rendered = template
                .Replace("[%transaction_id%]", transId)
                .Replace("[%client_ip%]", context.Request.IpAddress ?? "")
                .Replace("[%request_url%]", context.Request.Url.Path + context.Request.Url.QueryString)
                .Replace("[%request_method%]", context.Request.Method)
                .Replace("[%request_host%]", context.Request.Headers.GetValueOrDefault("Host", new[]{""})[0])
                .Replace("[%timestamp%]", DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ssZ"))
                .Replace("[%app_id%]", (string)context.Variables.GetValueOrDefault("rdwrAppId", ""));
              return rendered;
            }" />




















