set-header.value:
@{
              try {
                var body = context.Response.Body.As(preserveContent: true);
                return (body != null ? body.Length : 0).ToString();
              } catch { return "0"; }
            }

@{
              // bytes-sent = status line (~20 bytes) + serialized response
              // headers ("name: value\r\n" each) + final empty line (2 bytes)
              // + body. Matches NGINX $bytes_sent semantics. Without the
              // header term, this previously equalled x-rdwr-o2v-body-bytes-sent.
              // Fixed in v1.3.2 (2026-05-03).
              try {
                var body = context.Response.Body.As(preserveContent: true);
                int bodyLen = body != null ? body.Length : 0;
                int headerBytes = 0;
                if (context.Response.Headers != null) {
                  foreach (var h in context.Response.Headers) {
                    string name = h.Key ?? "";
                    string val = string.Join(", ", h.Value ?? new string[0]);
                    headerBytes += name.Length + 2 + val.Length + 2; // ": " + "\r\n"
                  }
                }
                const int statusLine = 20;
                const int finalCrlf = 2;
                return (statusLine + headerBytes + finalCrlf + bodyLen).ToString();
              } catch { return "0"; }
            }

@{
              var oop_log = (string)context.Variables.GetValueOrDefault("rdwrOopLog", "");
              if (oop_log == "3") {
                try {
                  var body = context.Response.Body.As(preserveContent: true);
                  if (body != null && body.Length > 0) {
                    return "application/octet-stream";
                  }
                } catch { }
              }
              return null;
            }

@{
              var oop_log = (string)context.Variables.GetValueOrDefault("rdwrOopLog", "");
              if (oop_log == "3") {
                try {
                  var body = context.Response.Body.As(preserveContent: true);
                  if (body != null && body.Length > 0) {
                    return "base64";
                  }
                } catch { }
              }
              return null;
            }

send-one-way-request.set-body:
@{
            var oop_log = (string)context.Variables.GetValueOrDefault("rdwrOopLog", "");
            if (oop_log == "3") {
              try {
                var body = context.Response.Body.As(preserveContent: true);
                if (body != null && body.Length > 0) {
                  int limit = 2048;
                  var limitStr = (string)context.Variables.GetValueOrDefault("rdwrOopLogBody", "2k");
                  if (!string.IsNullOrEmpty(limitStr)) {
                    limitStr = limitStr.Trim();
                    if (limitStr.EndsWith("k", StringComparison.OrdinalIgnoreCase)) {
                      limit = int.Parse(limitStr.TrimEnd('k','K')) * 1024;
                    } else if (limitStr.EndsWith("m", StringComparison.OrdinalIgnoreCase)) {
                      limit = int.Parse(limitStr.TrimEnd('m','M')) * 1024 * 1024;
                    } else {
                      int.TryParse(limitStr, out limit);
                    }
                  }
                  // Cap at the configured body max size
                  var maxBody = (long)context.Variables.GetValueOrDefault("rdwrBodyMaxSize", 100000L);
                  if (limit > maxBody) {
                    limit = (int)maxBody;
                  }
                  byte[] capture;
                  if (body.Length > limit) {
                    capture = new byte[limit];
                    System.Array.Copy(body, capture, limit);
                  } else {
                    capture = body;
                  }
                  return Convert.ToBase64String(capture);
                }
              } catch { }
            }
            return "";
          }
